import { readFileSync } from 'node:fs';
const toml = readFileSync('packages/agent-core/src/config/toml.ts','utf8');
const tele = readFileSync('apps/liora/src/cli/telemetry.ts','utf8');
const footer = readFileSync('apps/liora/src/tui/components/chrome/footer.ts','utf8');
const status = readFileSync('apps/liora/src/tui/components/messages/status-panel.ts','utf8');
const fails=[];
if (!toml.includes('Product telemetry is off by default (ZDR-friendly)')) fails.push('toml-default');
if (!tele.includes('config.telemetry === true')) fails.push('opt-in-only');
if (!tele.includes('return { telemetry: false }')) fails.push('safe-default');
if (!footer.includes('formatZdrFooterBadge')) fails.push('footer-zdr');
if (!status.includes('ZDR-friendly local')) fails.push('status-zdr');
if (fails.length) { console.error(fails.join(',')); process.exit(1);} console.log('zdr-source-ok');
